using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    #region CalculateTotal — DataRow tests

    [TestMethod]
    [DataRow("10.00", 1, "0.0", "10.00", DisplayName = "Single item, no tax")]
    [DataRow("10.00", 5, "0.0", "50.00", DisplayName = "Multiple items, no tax")]
    [DataRow("25.00", 2, "0.10", "55.00", DisplayName = "Two items, 10% tax")]
    [DataRow("99.99", 3, "0.08", "323.97", DisplayName = "Three items, 8% tax")]
    [DataRow("0.00", 10, "0.20", "0.00", DisplayName = "Zero price, any quantity")]
    [DataRow("50.00", 0, "0.15", "0.00", DisplayName = "Zero quantity returns zero")]
    [DataRow("100.00", 1, "1.0", "200.00", DisplayName = "100% tax doubles the price")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        string unitPriceStr, int quantity, string taxRateStr, string expectedStr)
    {
        var unitPrice = decimal.Parse(unitPriceStr);
        var taxRate = decimal.Parse(taxRateStr);
        var expected = decimal.Parse(expectedStr);

        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(-1, 1, "0.10", DisplayName = "Negative unit price throws")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        int unitPrice, int quantity, string taxRateStr)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, decimal.Parse(taxRateStr)));
    }

    [TestMethod]
    [DataRow("10.00", -1, "0.10", DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeQuantity_Throws(
        string unitPriceStr, int quantity, string taxRateStr)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(decimal.Parse(unitPriceStr), quantity, decimal.Parse(taxRateStr)));
    }

    [TestMethod]
    [DataRow("10.00", 1, "-0.01", DisplayName = "Tax rate below 0 throws")]
    [DataRow("10.00", 1, "1.01", DisplayName = "Tax rate above 1 throws")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        string unitPriceStr, int quantity, string taxRateStr)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(decimal.Parse(unitPriceStr), quantity, decimal.Parse(taxRateStr)));
    }

    #endregion

    #region CalculateTotal — DynamicData tests

    public static IEnumerable<object[]> BulkOrderTestData
    {
        get
        {
            yield return new object[] { 19.99m, 100, 0.07m, 2138.93m };
            yield return new object[] { 5.50m, 250, 0.05m, 1443.75m };
            yield return new object[] { 1000.00m, 1, 0.20m, 1200.00m };
        }
    }

    [TestMethod]
    [DynamicData(nameof(BulkOrderTestData))]
    public void CalculateTotal_BulkOrders_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    #endregion

    #region ApplyDiscount — DataRow tests

    [TestMethod]
    [DataRow("100.00", "0", "100.00", DisplayName = "0% discount — no change")]
    [DataRow("100.00", "10", "90.00", DisplayName = "10% discount")]
    [DataRow("100.00", "50", "50.00", DisplayName = "50% discount — half price")]
    [DataRow("100.00", "100", "0.00", DisplayName = "100% discount — free")]
    [DataRow("49.99", "25", "37.4925", DisplayName = "Fractional result")]
    [DataRow("200.00", "33.33", "133.34", DisplayName = "Non-round discount percent")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        string priceStr, string discountStr, string expectedStr)
    {
        var price = decimal.Parse(priceStr);
        var discount = decimal.Parse(discountStr);
        var expected = decimal.Parse(expectedStr);

        var result = _calculator.ApplyDiscount(price, discount);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow("100.00", "-1", DisplayName = "Negative discount throws")]
    [DataRow("100.00", "100.01", DisplayName = "Discount over 100 throws")]
    public void ApplyDiscount_InvalidDiscount_Throws(string priceStr, string discountStr)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(decimal.Parse(priceStr), decimal.Parse(discountStr)));
    }

    #endregion

    #region ApplyDiscount — DynamicData (method source)

    public static IEnumerable<object[]> GetTieredDiscountData()
    {
        // Simulates tiered pricing: higher order values get bigger discounts
        yield return new object[] { 50.00m, 5m, 47.50m };
        yield return new object[] { 150.00m, 10m, 135.00m };
        yield return new object[] { 500.00m, 15m, 425.00m };
        yield return new object[] { 1000.00m, 20m, 800.00m };
    }

    [TestMethod]
    [DynamicData(nameof(GetTieredDiscountData), DynamicDataSourceType.Method)]
    public void ApplyDiscount_TieredDiscounts_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    #endregion
}

